# === Atomic shortest-path primitives (pure, reusable) ===

def get_vertices(graph):
    """Representation-agnostic vertex list (networkx DiGraph or {u: [(v,w)]} dict)."""
    if isinstance(graph, dict):
        verts = set(graph.keys())
        for u in graph:
            for v, _w in graph[u]:
                verts.add(v)
        return sorted(verts)
    return list(graph.nodes())

def initialize_single_source(graph, s):
    """Return (dist, pi): dist[v]=INF except dist[s]=0; pi[v]=None for all v."""
    verts = get_vertices(graph)
    if s not in verts:
        raise ValueError(f"source {s!r} is not a vertex of the graph")
    dist = {v: math.inf for v in verts}
    pi = {v: None for v in verts}
    dist[s] = 0
    return dist, pi

def relax(u, v, w, dist, pi):
    """If the edge (u,v,w) improves v's estimate, update dist/pi and return True."""
    assert u in dist, f"{u!r} missing from dist map"
    assert v in dist, f"{v!r} missing from dist map"
    if dist[u] + w < dist[v]:
        dist[v] = dist[u] + w
        pi[v] = u
        return True
    return False

# Sanity check
d0, p0 = initialize_single_source(example_graph, "s")
assert d0["s"] == 0 and all(d0[v] == math.inf for v in get_vertices(example_graph) if v != "s")
assert all(p0[v] is None for v in get_vertices(example_graph))
_t = {"a": 0, "b": math.inf}; _p = {"a": None, "b": None}
assert relax("a", "b", 3, _t, _p) is True and _t["b"] == 3 and _p["b"] == "a"
assert relax("a", "b", 5, _t, _p) is False
print("Initialized distances from s:",
      {v: _fmt(d0[v]) for v in get_vertices(example_graph)})
print("relax() sanity check passed.")

# === Empirical array-vs-heap timing ===

def dijkstra_array(graph, s):
    """Dijkstra with a linear-array Extract-Min: O(V^2)."""
    dist, pi = initialize_single_source(graph, s)
    verts = get_vertices(graph)
    S = set()
    while len(S) < len(verts):
        u, best = None, math.inf
        for v in verts:           # linear scan for the minimum in V - S
            if v not in S and dist[v] < best:
                best, u = dist[v], v
        if u is None:             # remaining vertices unreachable
            break
        S.add(u)
        for v, w in neighbors(graph, u):
            relax(u, v, w, dist, pi)
    return dist

def dijkstra_heap(graph, s):
    """Dijkstra with a binary heap (no snapshot recording): O(E lg V)."""
    dist, pi = initialize_single_source(graph, s)
    S = set()
    pq = [(0, s)]
    while pq:
        d, u = heapq.heappop(pq)
        if u in S:
            continue
        S.add(u)
        for v, w in neighbors(graph, u):
            if relax(u, v, w, dist, pi):
                heapq.heappush(pq, (dist[v], v))
    return dist

def make_random_graph(n, density, max_w=20, seed=None):
    """Random DiGraph on vertices 0..n-1 with a spanning path 0->1->...->n-1
    so vertex 0 reaches everything; extra random non-negative edges by density."""
    rng = random.Random(seed)
    G = nx.DiGraph()
    G.add_nodes_from(range(n))
    perm = list(range(1, n))
    rng.shuffle(perm)
    chain = [0] + perm
    for a, b in zip(chain, chain[1:]):
        G.add_edge(a, b, weight=rng.randint(1, max_w))
    for u in range(n):
        for v in range(n):
            if u != v and not G.has_edge(u, v) and rng.random() < density:
                G.add_edge(u, v, weight=rng.randint(1, max_w))
    return G

def time_algorithm(fn, graph, s, repeats=3):
    best = math.inf
    for _ in range(repeats):
        t0 = time.perf_counter()
        fn(graph, s)
        best = min(best, time.perf_counter() - t0)
    return best

def run_timing_experiment(sizes, density):
    timings = {}
    for n in sizes:
        try:
            g = make_random_graph(n, density, seed=n)
            timings[n] = {
                "array": time_algorithm(dijkstra_array, g, 0),
                "heap": time_algorithm(dijkstra_heap, g, 0),
            }
        except Exception as e:  # skip a bad size rather than abort the sweep
            print(f"  size {n} skipped: {e}")
    return timings

# Correctness cross-check: array and heap agree on a shared graph
_g = make_random_graph(20, 0.3, seed=1)
assert dijkstra_array(_g, 0) == dijkstra_heap(_g, 0)
assert dijkstra_heap(example_graph, "s") == {"s": 0, "y": 5, "t": 8, "z": 7, "x": 9}

def run_and_plot(max_n=150, density=0.3):
    sizes = [n for n in [10, 25, 50, 100, 150] if n <= max_n]
    timings = run_timing_experiment(sizes, density)
    print(f"{'n':<6}{'array (ms)':<14}{'heap (ms)':<14}")
    for n in sizes:
        a = timings[n]["array"] * 1e3
        h = timings[n]["heap"] * 1e3
        print(f"{n:<6}{a:<14.3f}{h:<14.3f}")
    fig, ax = plt.subplots(figsize=(6.5, 4.5))
    ax.plot(sizes, [timings[n]["array"] * 1e3 for n in sizes], "o-", label="array  O(V^2)")
    ax.plot(sizes, [timings[n]["heap"] * 1e3 for n in sizes], "s-", label="binary heap  O(E lg V)")
    ax.set_xlabel("number of vertices |V|"); ax.set_ylabel("time (ms)")
    ax.set_title(f"Dijkstra runtime vs. graph size (density={density})")
    ax.legend(); ax.grid(True, alpha=0.3)
    plt.show()
    return timings

if HAVE_WIDGETS and _in_ipython():
    interact(run_and_plot,
             max_n=IntSlider(min=25, max=150, step=25, value=150, description="max |V|"),
             density=IntSlider(min=10, max=80, step=10, value=30, description="density %"))
    # note: density slider is in %; wrap to fraction
    def _wrapped(max_n, density):
        return run_and_plot(max_n=max_n, density=density / 100.0)
else:
    run_and_plot()
